    "public static Locale toLocale(final String str) {
        if (str == null) {
            return null;
        }
        final int len = str.length();
        if (len < 2) {
            throw new IllegalArgumentException("Invalid locale format: " + str);
        }
        final char ch0 = str.charAt(0);
        final char ch1 = str.charAt(1);
        if (!Character.isLowerCase(ch0) || !Character.isLowerCase(ch1)) {
            throw new IllegalArgumentException("Invalid locale format: " + str);
        }
        if (len == 2) {
            return new Locale(str);
        }
        if (len < 5) {
            throw new IllegalArgumentException("Invalid locale format: " + str);
        }
        if (str.charAt(2) != '_') {
            throw new IllegalArgumentException("Invalid locale format: " + str);
        }
        final char ch3 = str.charAt(3);
        if (ch3 == '_') {
            return new Locale(str.substring(0, 2), "", str.substring(4));
        }
        final char ch4 = str.charAt(4);
        // Support alpha 2-letter country
        if (Character.isUpperCase(ch3) && Character.isUpperCase(ch4)) {
            if (len == 5) {
                return new Locale(str.substring(0, 2), str.substring(3, 5));
            }
            if (len < 7) {
                throw new IllegalArgumentException("Invalid locale format: " + str);
            }
            if (str.charAt(5) != '_') {
                throw new IllegalArgumentException("Invalid locale format: " + str);
            }
            return new Locale(str.substring(0, 2), str.substring(3, 5), str.substring(6));
        }
        // Support numeric 3-digit country (UN M.49)
        if (Character.isDigit(ch3) && Character.isDigit(ch4) && len >= 6 && Character.isDigit(str.charAt(5))) {
            if (len == 6) {
                return new Locale(str.substring(0, 2), str.substring(3, 6));
            }
            if (len < 8) {
                throw new IllegalArgumentException("Invalid locale format: " + str);
            }
            if (str.charAt(6) != '_') {
                throw new IllegalArgumentException("Invalid locale format: " + str);
            }
            return new Locale(str.substring(0, 2), str.substring(3, 6), str.substring(7));
        }
        throw new IllegalArgumentException("Invalid locale format: " + str);
    }"
